// Helper using jsPDF (if loaded) to draw a mock GSTR-3B layout
window.generateGstr3bMockPdfBlob = function(monthData) {
  if (typeof window.jspdf === 'undefined') {
    console.error("jsPDF is not loaded. Cannot generate mock PDF.");
    return null;
  }
  
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();
  
  // Set nice fonts & colors
  doc.setFont("helvetica", "bold");
  doc.setFontSize(16);
  doc.setTextColor(26, 54, 93); // Navy
  doc.text("FORM GSTR-3B", 14, 15);
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(100, 100, 100);
  doc.text(`[See Rule 61(5)] · Period: ${monthData.period}`, 14, 21);
  doc.text(`File Ref: ${monthData.filename}`, 14, 25);
  
  // Render GSTIN block
  doc.setDrawColor(200, 200, 200);
  doc.setFillColor(245, 245, 245);
  doc.rect(14, 30, 182, 10, 'F');
  doc.setFont("helvetica", "bold");
  doc.setTextColor(0, 0, 0);
  doc.text("GSTIN: 27AAAAA0000A1Z5   |   Legal Name: ACME ENTERPRISES PRIVATE LIMITED", 18, 36);
  
  // Render Table 3.1 title
  doc.setFontSize(11);
  doc.setTextColor(26, 54, 93);
  doc.text("3.1 Details of Outward Supplies and inward supplies liable to reverse charge", 14, 48);
  
  // Table Headers
  const yStart = 53;
  doc.setFillColor(43, 108, 176); // Steel Blue
  doc.rect(14, yStart, 182, 12, 'F');
  doc.setFontSize(8);
  doc.setTextColor(255, 255, 255);
  doc.setFont("helvetica", "bold");
  doc.text("Nature of Supplies", 16, yStart + 8);
  doc.text("Taxable Value", 85, yStart + 8);
  doc.text("IGST (Integrated)", 115, yStart + 8);
  doc.text("CGST (Central)", 140, yStart + 8);
  doc.text("SGST (State)", 165, yStart + 8);
  doc.text("Cess", 185, yStart + 8);
  
  // Table Rows (a to e) and 3.1.1
  const rows = [
    { key: "3.1(a)", label: "(a) Outward taxable supplies (other than zero rated, nil rated and exempted)" },
    { key: "3.1(b)", label: "(b) Outward taxable supplies (zero rated)" },
    { key: "3.1(c)", label: "(c) Other outward supplies (Nil rated, exempted)" },
    { key: "3.1(d)", label: "(d) Inward supplies (liable to Reverse Charge)" },
    { key: "3.1(e)", label: "(e) Non-GST outward supplies" },
    { key: "3.1.1(i)", label: "3.1.1(i) Taxable supplies on which operator is liable to pay tax u/s 9(5)" }
  ];
  
  let currentY = yStart + 12;
  doc.setTextColor(0, 0, 0);
  
  rows.forEach((r, idx) => {
    // Alternating background
    if (idx % 2 === 1) {
      doc.setFillColor(248, 250, 252);
      doc.rect(14, currentY, 182, 10, 'F');
    }
    
    // Grid line
    doc.setDrawColor(226, 232, 240);
    doc.line(14, currentY + 10, 196, currentY + 10);
    
    doc.setFont("helvetica", "normal");
    
    // Wrap text if needed, but for table display keep it tight
    const textLabel = doc.splitTextToSize(r.label, 65);
    doc.text(textLabel, 16, currentY + 6);
    
    // Numbers
    const vals = monthData.data[r.key];
    doc.setFont("helvetica", "bold");
    doc.text(vals.taxable.toFixed(2), 85, currentY + 6);
    doc.text(vals.igst.toFixed(2), 115, currentY + 6);
    doc.text(vals.cgst.toFixed(2), 140, currentY + 6);
    doc.text(vals.sgst.toFixed(2), 165, currentY + 6);
    doc.text(vals.cess.toFixed(2), 185, currentY + 6);
    
    currentY += 10;
  });
  
  // Draw Table 5.1: Interest & Late fee payable
  currentY += 10;
  doc.setFontSize(11);
  doc.setTextColor(26, 54, 93);
  doc.setFont("helvetica", "bold");
  doc.text("5.1 Interest & Late fee payable", 14, currentY);
  
  currentY += 4;
  doc.setFillColor(100, 110, 120);
  doc.rect(14, currentY, 182, 10, 'F');
  doc.setFontSize(8);
  doc.setTextColor(255, 255, 255);
  doc.text("Description", 16, currentY + 7);
  doc.text("Integrated Tax", 85, currentY + 7);
  doc.text("Central Tax", 115, currentY + 7);
  doc.text("State/UT Tax", 145, currentY + 7);
  doc.text("Cess", 175, currentY + 7);
  
  doc.setTextColor(0, 0, 0);
  
  // Row 1: Interest
  currentY += 10;
  doc.setDrawColor(226, 232, 240);
  doc.line(14, currentY + 10, 196, currentY + 10);
  doc.text("Interest", 16, currentY + 6);
  doc.text(monthData.t51.interest.igst.toFixed(2), 85, currentY + 6);
  doc.text(monthData.t51.interest.cgst.toFixed(2), 115, currentY + 6);
  doc.text(monthData.t51.interest.sgst.toFixed(2), 145, currentY + 6);
  doc.text(monthData.t51.interest.cess.toFixed(2), 175, currentY + 6);
  
  // Row 2: Late fee
  currentY += 10;
  doc.line(14, currentY + 10, 196, currentY + 10);
  doc.text("Late fee", 16, currentY + 6);
  doc.text(monthData.t51.latefee.igst.toFixed(2), 85, currentY + 6);
  doc.text(monthData.t51.latefee.cgst.toFixed(2), 115, currentY + 6);
  doc.text(monthData.t51.latefee.sgst.toFixed(2), 145, currentY + 6);
  doc.text(monthData.t51.latefee.cess.toFixed(2), 175, currentY + 6);

  // Draw Table 6.1: Payment of Tax (simplified to extract cash/itc)
  currentY += 10;
  doc.setFontSize(11);
  doc.setTextColor(26, 54, 93);
  doc.setFont("helvetica", "bold");
  doc.text("6.1 Payment of tax (Interest / Fees / ITC Utilisation)", 14, currentY);
  
  currentY += 4;
  doc.setFillColor(74, 85, 104); // Slate Grey
  doc.rect(14, currentY, 182, 10, 'F');
  doc.setFontSize(8);
  doc.setTextColor(255, 255, 255);
  doc.text("Description (Paid through ITC / Cash)", 16, currentY + 7);
  doc.text("Integrated Tax", 85, currentY + 7);
  doc.text("Central Tax", 115, currentY + 7);
  doc.text("State/UT Tax", 145, currentY + 7);
  doc.text("Cess", 175, currentY + 7);
  
  doc.setTextColor(0, 0, 0);
  
  // Row 1: Paid through ITC
  currentY += 10;
  doc.setDrawColor(226, 232, 240);
  doc.line(14, currentY + 10, 196, currentY + 10);
  doc.text("Paid through ITC (Integrated/Central/State/Cess)", 16, currentY + 6);
  doc.text(monthData.payment.itc.igst.toFixed(2), 85, currentY + 6);
  doc.text(monthData.payment.itc.cgst.toFixed(2), 115, currentY + 6);
  doc.text(monthData.payment.itc.sgst.toFixed(2), 145, currentY + 6);
  doc.text(monthData.payment.itc.cess.toFixed(2), 175, currentY + 6);
  
  // Row 2: Paid in Cash
  currentY += 10;
  doc.line(14, currentY + 10, 196, currentY + 10);
  doc.text("Tax paid in cash (Net Liability Discharged)", 16, currentY + 6);
  doc.text(monthData.payment.cash.igst.toFixed(2), 85, currentY + 6);
  doc.text(monthData.payment.cash.cgst.toFixed(2), 115, currentY + 6);
  doc.text(monthData.payment.cash.sgst.toFixed(2), 145, currentY + 6);
  doc.text(monthData.payment.cash.cess.toFixed(2), 175, currentY + 6);
  
  return doc.output('blob');
};

// Inject mock Table 5.1 data for all periods if not present
window.GSTR_SAMPLE_DATA.forEach((period, idx) => {
  const monthNum = idx + 1;
  if (!period.t51) {
    period.t51 = {
      interest: {
        igst: Math.round(100.0 * monthNum * 100) / 100,
        cgst: Math.round(50.0 * monthNum * 100) / 100,
        sgst: Math.round(50.0 * monthNum * 100) / 100,
        cess: 0.00
      },
      latefee: {
        igst: 0.00,
        cgst: Math.round(25.0 * monthNum * 100) / 100,
        sgst: Math.round(25.0 * monthNum * 100) / 100,
        cess: 0.00
      }
    };
  }
});
